import torch
from torchvision import models
from torchvision import transforms
import torchvision.datasets as dsets
from PIL import Image
import requests
import os

# List of pre-trained model checkpoints
model_urls = {
    'vgg16': 'https://download.pytorch.org/models/vgg16-397923ed.pth',
    'resnet18': 'https://download.pytorch.org/models/resnet18-5c106cde.pth'
}

def download_pretrained_model(model_name):
    if model_name not in model_urls:
        raise ValueError(f"Model {model_name} is not supported")
    
    url = model_urls[model_name]
    r = requests.get(url, allow_redirects=True)
    open(os.path.join('models', f'{model_name}.pth'), 'wb').write(r.content)

def fine_tune_model(model_name):
    # Download the pre-trained model checkpoint
    download_pretrained_model(model_name)
    
    # Load the downloaded model checkpoint
    model = models.__dict__[model_name](pretrained=True)
    state_dict = torch.load(os.path.join('models', f'{model_name}.pth'), map_location='cpu')
    model.load_state_dict(state_dict)
    
    # Freeze all model weights except for the last layer
    for param in model.parameters():
        param.requires_grad = False
    
    # Define custom dataset and data loader
    transform = transforms.Compose([transforms.Resize(224),
                                    transforms.CenterCrop(224),
                                    transforms.ToTensor(),
                                    transforms.Normalize(mean=[0.485, 0.456, 0.406],
                                                         std=[0.229, 0.224, 0.225])])
    
    dataset = dsets.ImageFolder('custom_dataset', transform=transform)
    data_loader = torch.utils.data.DataLoader(dataset, batch_size=32, shuffle=True)
    
    # Fine-tune the model on custom dataset
    for epoch in range(10):
        model.train()
        total_loss = 0
        for i, (images, labels) in enumerate(data_loader):
            output = model(images)
            loss_fn = torch.nn.CrossEntropyLoss()
            loss = loss_fn(output, labels)
            optimizer = torch.optim.Adam(model.fc.parameters(), lr=1e-5)
            optimizer.zero_grad()
            loss.backward()
            optimizer.step()
            total_loss += loss.item()
        print(f'Epoch {epoch+1}, Loss: {total_loss / len(data_loader)}')

# Example usage
fine_tune_model('vgg16')